  ?statement ps:P2709 ?series.
  ?statement pq:P2557 ?result.
  BIND(STRBEFORE(?result, '-') AS ?wins_str)
  BIND(STRAFTER(?result, '-') AS ?losses_str)
  BIND(STRTOINT(?wins_str) AS ?wins)
  BIND(STRTOINT(?losses_str) AS ?losses)
}

